#!/usr/bin/env node

const { execSync } = require('child_process');

/**
 * CI/CD dependency installation script
 * 
 * Security considerations:
 * - Uses `npm ci` instead of `npm install` for deterministic, lockfile-based installs
 * - Uses `--ignore-scripts` to prevent arbitrary code execution from postinstall hooks
 * - Explicitly runs only our own postinstall script defined in our package.json (if it exists)
 */

function runCommand(command, description) {
  console.log(`\n=== ${description} ===`);
  console.log(`Running: ${command}`);
  try {
    execSync(command, { stdio: 'inherit', env: { ...process.env } });
    console.log(`✓ ${description} completed successfully.`);
  } catch (error) {
    console.error(`✗ ${description} failed with exit code ${error.status}`);
    process.exit(error.status || 1);
  }
}

function main() {
  console.log('Starting CI/CD dependency installation...');
  console.log(`Node version: ${process.version}`);
  execSync('npm --version', { stdio: 'inherit' });

  // Step 1: Install dependencies using `npm ci` with --ignore-scripts
  // `npm ci` ensures installs are reproducible from package-lock.json,
  // preventing supply chain attacks from modified/unpinned dependencies.
  // `--ignore-scripts` prevents execution of arbitrary lifecycle scripts
  // from third-party packages (a common supply chain attack vector).
  runCommand(
    'npm ci --ignore-scripts',
    'Installing dependencies (deterministic, scripts disabled)'
  );

  // Step 2: Run only our own project's postinstall script if defined.
  // We do NOT blindly run all package lifecycle hooks, as those can
  // execute arbitrary code from third-party packages.
  try {
    const packageJson = require(`${process.cwd()}/package.json`);
    if (packageJson.scripts && packageJson.scripts.postinstall) {
      runCommand(
        'npm run postinstall',
        'Running project-level postinstall script'
      );
    } else {
      console.log('\nNo project-level postinstall script defined. Skipping.');
    }
  } catch (err) {
    console.error('Warning: Could not read package.json to check for postinstall script.');
  }

  // Step 3: Run npm audit to surface known vulnerabilities
  console.log('\n=== Running dependency audit ===');
  try {
    execSync('npm audit --audit-level=high', { stdio: 'inherit' });
    console.log('✓ No high/critical vulnerabilities found.');
  } catch (error) {
    console.warn('⚠ npm audit found vulnerabilities. Review the output above.');
    // Don't fail the build on audit warnings, but log them
  }

  console.log('\n=== CI/CD dependency installation complete ===');
}

main();